  function updateRisk(){const s=equitySnapshot(),alloc=allocationData(),maxAlloc=Math.max(0,...alloc.filter(x=>x.name!=='USDT').map(x=>x.pct)),perps=Object.values(account.positions).filter(x=>x.type==='perp'),margin=perps.reduce((a,x)=>a+x.margin,0),marginRate=s.equity?margin/s.equity*100:0,drawdown=calculateDrawdown(account.equityHistory.map(x=>x.v)),score=clamp(Math.round(92-maxAlloc*.38-marginRate*.45-drawdown*1.2-account.orders.length*1.5),25,96),label=score>=80?'稳健':score>=60?'中等':'偏高';setText('#riskScore',score);setText('#sideRisk',score);setText('#riskScoreLabel',label);setText('#riskLevel',label);setText('#riskHint',maxAlloc?`最高集中度 ${maxAlloc.toFixed(0)}%`:'暂无持仓风险');setText('#riskScoreDesc',score>=80?'当前模拟账户仓位与保证金使用处于稳健区间。':score>=60?'仓位集中度或保证金使用需要持续关注。':'账户风险偏高，建议降低集中度和杠杆。');$("#riskRing").style.background=`radial-gradient(circle,var(--panel) 59%,transparent 61%),conic-gradient(${score>=80?'var(--green)':score>=60?'var(--amber)':'var(--red)'} 0 ${score}%,var(--panel-3) ${score}%)`;setText('#marginRate',`${marginRate.toFixed(0)}%`);$("#marginBar").style.width=`${clamp(marginRate,0,100)}%`;setText('#concentrationRate',`${maxAlloc.toFixed(0)}%`);$("#concentrationBar").style.width=`${clamp(maxAlloc,0,100)}%`;const badge=$("#tradeRiskBadge");badge.textContent=label;badge.className=score>=80?'good':score>=60?'warn':'bad';generateInsights(score,maxAlloc,marginRate,drawdown)}
  function generateInsights(score,maxAlloc,marginRate,drawdown){const markets=PAIRS.map(p=>({p,m:getMarket(p.instId)})).sort((a,b)=>b.m.change-a.m.change),best=markets[0],worst=markets[markets.length-1],avg=markets.reduce((s,x)=>s+x.m.change,0)/markets.length,s=equitySnapshot(),headline=avg>1?'主流资产整体走强，账户风险仍需服从仓位纪律':avg<-1?'市场短线承压，优先控制回撤而非追求交易频率':'市场处于震荡区间，账户风险总体可控';setText('#insightHeadline',headline);setText('#insightSummary',`当前主流资产平均 24 小时涨跌幅为 ${pct(avg)}，表现最强的是 ${best.p.base}（${pct(best.m.change)}），表现最弱的是 ${worst.p.base}（${pct(worst.m.change)}）。模拟账户权益为 ${money(s.equity)}，最高非稳定币集中度 ${maxAlloc.toFixed(1)}%，保证金占用 ${marginRate.toFixed(1)}%。`);setText('#overviewAiBrief',`${best.p.base} 当前领涨主流资产，${worst.p.base} 相对偏弱。账户综合风险评分 ${score}，${score>=80?'整体处于稳健区间':'建议降低集中度或杠杆暴露'}。`);setText('#insightTime',`更新于 ${fmtTime()}`);$("#insightTags").innerHTML=[`行情源 ${state.marketSource||'连接中'}`,`市场均值 ${pct(avg)}`,`风险评分 ${score}`,`最大回撤 ${drawdown.toFixed(2)}%`].map(x=>`<span>${x}</span>`).join('');const diagnosis=[['!', '仓位集中度',maxAlloc?`当前最高单项风险资产占比 ${maxAlloc.toFixed(1)}%。`:'当前没有非稳定币持仓。',maxAlloc>45?'高':maxAlloc>30?'中':'低',maxAlloc>45?'negative':maxAlloc>30?'warn':'positive'],['↘','账户回撤',`历史模拟权益最大回撤约 ${drawdown.toFixed(2)}%。`,drawdown>12?'高':drawdown>6?'中':'低',drawdown>12?'negative':drawdown>6?'warn':'positive'],['◇','保证金使用',`永续模拟保证金占权益 ${marginRate.toFixed(1)}%。`,marginRate>35?'高':marginRate>15?'中':'低',marginRate>35?'negative':marginRate>15?'warn':'positive'],['⌁','市场波动',`主流资产平均变化 ${pct(avg)}，当前偏${Math.abs(avg)<.8?'震荡':avg>0?'强势':'弱势'}。`,Math.abs(avg)>4?'高':Math.abs(avg)>2?'中':'低',Math.abs(avg)>4?'negative':Math.abs(avg)>2?'warn':'positive']];$("#diagnosisList").innerHTML=diagnosis.map(x=>`<div class="diagnosis-item"><span class="diagnosis-icon">${x[0]}</span><div><b>${x[1]}</b><p>${x[2]}</p></div><em class="${x[4]}">${x[3]}风险</em></div>`).join('');$("#riskIndicators").innerHTML=[['集中度',maxAlloc],['保证金',marginRate],['回撤',Math.min(drawdown*4,100)],['委托暴露',Math.min(account.orders.length*15,100)]].map(([n,v])=>`<div class="risk-indicator"><div><span>${n}</span><strong>${Number(v).toFixed(1)}%</strong></div><div class="indicator-bar"><i style="width:${clamp(v,0,100)}%"></i></div></div>`).join('');const buys=account.trades.filter(t=>t.side==='buy').length,sells=account.trades.filter(t=>t.side==='sell').length;$("#behaviorMatrix").innerHTML=[['交易频率',account.trades.length,account.trades.length>20?'偏高':'正常'],['买卖比例',`${buys}:${sells}`,Math.abs(buys-sells)>5?'失衡':'均衡'],['未成交委托',account.orders.length,account.orders.length>5?'偏多':'正常'],['使用杠杆',Object.values(account.positions).some(x=>x.type==='perp')?'是':'否',marginRate>25?'关注':'可控']].map(x=>`<div class="behavior-row"><span>${x[0]}</span><strong>${x[1]}</strong><em>${x[2]}</em></div>`).join('')}
  function renderBots(){$("#botGrid").innerHTML=state.bots.map(b=>`<article class="card bot-card"><div class="bot-head"><span class="bot-icon">${b.icon}</span><button class="switch ${b.running?'on':''}" data-bot-toggle="${b.id}"><i></i></button></div><h3>${b.name}</h3><p>${b.desc}</p><div class="bot-metrics"><div><span>模拟收益</span><strong class="positive">+${b.ret.toFixed(2)}%</strong></div><div><span>最大回撤</span><strong>${b.dd.toFixed(2)}%</strong></div><div><span>胜率</span><strong>${b.win.toFixed(1)}%</strong></div></div></article>`).join('');$("#strategyRankBody").innerHTML=[...state.bots].sort((a,b)=>b.ret-a.ret).map(b=>`<tr><td><strong>${b.name}</strong></td><td>${b.market}</td><td class="positive">+${b.ret.toFixed(2)}%</td><td>${b.dd.toFixed(2)}%</td><td>${b.win.toFixed(1)}%</td><td class="${b.running?'positive':'neutral'}">${b.running?'运行中':'已暂停'}</td></tr>`).join('');setText('#runningBots',state.bots.filter(x=>x.running).length);$$('[data-bot-toggle]').forEach(btn=>btn.onclick=()=>{const bot=state.bots.find(x=>x.id===btn.dataset.botToggle);bot.running=!bot.running;renderBots();toast(bot.running?'策略已开始模拟运行':'策略已暂停')})}
  function updateAllMarketViews(){PAIRS.forEach(p=>{const arr=state.sparkData[p.instId]||[];if(!arr.length&&getMarket(p.instId).last){const base=getMarket(p.instId).last,ch=getMarket(p.instId).change;state.sparkData[p.instId]=Array.from({length:26},(_,i)=>base*(1+(Math.sin(i/2.7)*.0018+(i/25-.5)*ch/100*.45)))}});updateTickerStrip();renderMarkets();updateOverviewMarket();updateSummaryCards();updateTradeHeader();renderPairMenu();updateAccountViews();if(!state.book.asks.length){const px=currentPrice()||68000;state.book.asks=Array.from({length:8},(_,i)=>[px+(i+1)*px*.00008,.03+i*.012]);state.book.bids=Array.from({length:8},(_,i)=>[px-(i+1)*px*.00008,.025+i*.011]);renderOrderBook()}}

  function navigate(page){if(!$("#page-"+page))return;state.page=page;$$('.page').forEach(x=>x.classList.toggle('active',x.id===`page-${page}`));$$('[data-page-link]').forEach(x=>x.classList.toggle('active',x.dataset.pageLink===page));$("#sidebar").classList.remove('show');window.scrollTo({top:0,behavior:'smooth'});if(page==='trade')setTimeout(()=>{if(state.chart)state.chart.applyOptions({width:$("#tradeChart").clientWidth,height:$("#tradeChart").clientHeight});else loadChart().catch(()=>toast('K线数据加载失败'))},80);if(page==='assets')drawEquityCharts()}
  function toast(message){const el=$("#toast");el.textContent=message;el.classList.add('show');clearTimeout(window.__atlasToast);window.__atlasToast=setTimeout(()=>el.classList.remove('show'),2400)}
  function exportReport(){const s=equitySnapshot(),report={generatedAt:new Date().toISOString(),product:'ATLAS X Demo',marketSource:state.marketSource,account:{equity:s.equity,cash:account.cash,unrealizedPnl:s.unrealized,positions:account.positions,orders:account.orders,trades:account.trades},notice:'本报告来自模拟账户，不构成投资建议。'},blob=new Blob([JSON.stringify(report,null,2)],{type:'application/json'}),a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=`atlas-x-report-${Date.now()}.json`;a.click();URL.revokeObjectURL(a.href);toast('模拟账户报告已导出')}

  function bindEvents(){$$('[data-page-link]').forEach(btn=>btn.onclick=()=>navigate(btn.dataset.pageLink));$("#mobileMenuBtn").onclick=()=>$("#sidebar").classList.toggle('show');$("#themeButton").onclick=()=>{document.body.classList.toggle('light');localStorage.setItem('atlas-theme',document.body.classList.contains('light')?'light':'dark');if(state.chart)state.chart.applyOptions({layout:{background:{type:'solid',color:getCss('--bg-elev')},textColor:getCss('--muted')},grid:{vertLines:{color:getCss('--line-soft')},horzLines:{color:getCss('--line-soft')}}});drawEquityCharts();updateSummaryCards();updateOverviewMarket()};if(localStorage.getItem('atlas-theme')==='light')document.body.classList.add('light');$("#pairSelectorBtn").onclick=e=>{const rect=e.currentTarget.getBoundingClientRect(),menu=$("#pairMenu");menu.style.left=`${rect.left}px`;menu.style.top=`${rect.bottom+5}px`;menu.classList.toggle('show')};document.addEventListener('click',e=>{if(!e.target.closest('#pairSelectorBtn')&&!e.target.closest('#pairMenu'))$("#pairMenu").classList.remove('show')});$$('#timeframeButtons button').forEach(btn=>btn.onclick=async()=>{$$('#timeframeButtons button').forEach(x=>x.classList.remove('active'));btn.classList.add('active');state.currentBar=btn.dataset.bar;try{await loadChart();connectRealtime()}catch{toast('该周期 K 线加载失败')}});$("#fitChartBtn").onclick=()=>state.chart?.timeScale().fitContent();$("#realtimeBtn").onclick=()=>state.chart?.timeScale().scrollToRealTime();$("#toggleMaBtn").onclick=()=>{state.maVisible=!state.maVisible;$("#toggleMaBtn").classList.toggle('active',state.maVisible);state.ma7Series?.applyOptions({visible:state.maVisible});state.ma25Series?.applyOptions({visible:state.maVisible})};$("#fullscreenChartBtn").onclick=()=>{const panel=$('.chart-panel');panel.classList.toggle('chart-fullscreen');$("#fullscreenChartBtn").textContent=panel.classList.contains('chart-fullscreen')?'退出全屏':'全屏';setTimeout(()=>state.chart?.applyOptions({width:$("#tradeChart").clientWidth,height:$("#tradeChart").clientHeight}),80)};$$('#productTabs button').forEach(btn=>btn.onclick=()=>{$$('#productTabs button').forEach(x=>x.classList.remove('active'));btn.classList.add('active');state.product=btn.dataset.product;updateOrderForm()});$$('#orderTypeTabs button').forEach(btn=>btn.onclick=()=>{$$('#orderTypeTabs button').forEach(x=>x.classList.remove('active'));btn.classList.add('active');state.orderType=btn.dataset.orderType;updateOrderForm()});$$('#buySellTabs button').forEach(btn=>btn.onclick=()=>{$$('#buySellTabs button').forEach(x=>x.classList.remove('active'));btn.classList.add('active');state.side=btn.dataset.side;updateOrderForm()});['#orderPrice','#orderAmount','#leverageSelect'].forEach(sel=>$(sel).addEventListener('input',updateOrderForm));$("#orderRange").oninput=e=>{$("#orderAmount").value=amountByRange(Number(e.target.value)).toFixed(getPair().base==='BTC'?6:4);updateOrderForm()};$("#submitOrderBtn").onclick=submitOrder;$$('#positionTabs button').forEach(btn=>btn.onclick=()=>{$$('#positionTabs button').forEach(x=>x.classList.remove('active'));btn.classList.add('active');state.positionTab=btn.dataset.positionTab;renderPositions()});$$('#marketTabs button').forEach(btn=>btn.onclick=()=>{$$('#marketTabs button').forEach(x=>x.classList.remove('active'));btn.classList.add('active');state.marketFilter=btn.dataset.filter;renderMarkets()});$("#marketSearch").oninput=renderMarkets;$("#resetAccountBtn").onclick=()=>$("#resetModal").hidden=false;$$('[data-close-modal]').forEach(x=>x.onclick=()=>$("#resetModal").hidden=true);$("#confirmResetBtn").onclick=()=>{account=defaultAccount();saveAccount();$("#resetModal").hidden=true;updateAccountViews();toast('模拟账户已重置')};$("#equityRange").onclick=e=>{if(!e.target.dataset.range)return;$$('#equityRange button').forEach(x=>x.classList.remove('active'));e.target.classList.add('active');drawEquityCharts()};$("#createBotBtn").onclick=()=>toast('演示版已展示策略创建入口');$("#refreshInsightBtn").onclick=()=>{updateRisk();toast('AI 洞察已基于最新数据重新生成')};$("#exportAccountBtn").onclick=exportReport;window.addEventListener('resize',()=>{drawEquityCharts();updateSummaryCards();updateOverviewMarket()})}
  async function init(){bindEvents();renderBots();renderPositions();renderPairMenu();updateOrderForm();updateAccountViews();try{await fetchMarkets();await loadChart();connectRealtime();state.pollTimer=setInterval(()=>fetchMarkets().catch(()=>{}),30000)}catch(e){console.error(e);toast('实时行情暂时连接失败，页面将自动重试');state.reconnectTimer=setTimeout(initRetry,5000)}}
